#include <bits/stdc++.h>
using namespace std;
int main() {
	int a, b, d = 0, f = 0;
	string c;
	cin >> a >> b >> c;
	if (a + b > c.size()) {
		cout << "-1";
		return 0;
	}
	for (int i = 0; i < c.size(); i++) {
		if (c[i] == 'S') {
			d++;
		} else f++;

	}
	if (a < d && b < f) {
		cout << 0;
		return 0;
	}
	d = abs(a - d);
	f = abs(b - f);

	cout << min(d, f);
	return 0;

}
